// Vanilla S01PacketJoinGame definition:
package net.minecraft.network.play.server;

public class S01PacketJoinGame implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private boolean hardcoreMode;
    private WorldSettings.GameType gameType;
    private int dimension;
    private EnumDifficulty difficulty;
    private int maxPlayers;
    private WorldType worldType;
    private boolean reducedDebugInfo;

    public void processPacket(INetHandlerPlayClient handler) {
        handler.handleJoinGame(this);
    }

    public int getEntityId() { return this.entityId; }
    public WorldSettings.GameType getGameType() { return this.gameType; }
    public int getDimension() { return this.dimension; }
    public EnumDifficulty getDifficulty() { return this.difficulty; }
    public int getMaxPlayers() { return this.maxPlayers; }
    public WorldType getWorldType() { return this.worldType; }
    public boolean isReducedDebugInfo() { return this.reducedDebugInfo; }
}

